916	/// Build a string from `s` by replacing `pat` with `repl`, push it on the stack,
917	/// and return the bytes of the pushed string.
918	///
919	/// C: `LUALIB_API const char *luaL_gsub(lua_State *L, const char *s, const char *p, const char *r)`
920	pub fn gsub<'a>(
921	    state: &'a mut LuaState,
922	    s: &[u8],
923	    pat: &[u8],
924	    repl: &[u8],
925	) -> Result<Vec<u8>, LuaError> {
926	    let mut b = LuaBuffer::new();
927	    buf_init(state, &mut b);
928	    add_gsub(&mut b, s, pat, repl);
929	    push_result(state, &mut b)?;
930	    // C: return lua_tostring(L, -1);
931	    Ok(state.peek_bytes(-1).unwrap_or_default())
932	}
