1781	/// C: `static void packint(luaL_Buffer *b, lua_Unsigned n, int islittle, int size, int neg)`
1782	fn packint(buf: &mut Vec<u8>, mut n: u64, is_little: bool, size: usize, neg: bool) {
1783	    let start = buf.len();
1784	    buf.resize(start + size, 0);
1785	    let slice = &mut buf[start..start + size];
1786	    // Write LSB first (little-endian), then swap if big-endian
1787	    for i in 0..size {
1788	        slice[if is_little { i } else { size - 1 - i }] = (n & MC as u64) as u8;
