1802	fn copywithendian(dest: &mut [u8], src: &[u8], is_little: bool) {
1803	    debug_assert_eq!(dest.len(), src.len());
1804	    if is_little == cfg!(target_endian = "little") {
1805	        dest.copy_from_slice(src);
1806	    } else {
