1816	fn unpackint(state: &LuaState, data: &[u8], is_little: bool, size: usize, is_signed: bool) -> Result<i64, LuaError> {
1817	    let limit = size.min(SZINT);
1818	    let mut res: u64 = 0;
1819	    for i in (0..limit).rev() {
1820	        res <<= NB;
1821	        let byte_idx = if is_little { i } else { size - 1 - i };
1822	        res |= data[byte_idx] as u64;
1823	    }
1824	
1825	    if size < SZINT {
1826	        if is_signed {
1827	            let mask: u64 = 1u64 << (size * NB as usize - 1);
1828	            res = res.wrapping_add((!res & (mask - 1)).wrapping_add(1) & mask.wrapping_neg())
1829	                .wrapping_sub(mask)
1830	                .wrapping_add(mask);
1831	            // Simpler: two's-complement sign extension
1832	            let mask2: u64 = 1u64 << (size * 8 - 1);
1833	            if res & mask2 != 0 {
1834	                res |= !((mask2 << 1) - 1);
1835	            }
1836	        }
1837	    } else if size > SZINT {
1838	        let mask = if !is_signed || (res as i64) >= 0 { 0u8 } else { MC };
